0721学习记录 今天集训休息，自己看了看代码源的视频补知识点
kmp相关 子串查询 输入两个字符串s,p,查询p是否在s中出现,若出现输出出现位置,否则输出-1
简化版
#include &lt;bits/stdc++.h&gt; using namespace std; string s,p; int nxt[100001],f[100001],n,m; void kmp(){ n=s.size(); m=p.size(); int j=0; nxt[0]=0; p=p+&#34;#&#34;+s; for(int i=1;i&lt;m+n+1;i++){ while(j&amp;&amp;p[i]!=p[j]) j=nxt[j-1]; if(p[i]==p[j]) j++; nxt[i]=j; } for(int i=m+1;i&lt;n+m+1;i++){ if(nxt[i]==m)cout&lt;&lt;i-2*m+1&lt;&lt;endl; } } int main(){ cin&gt;&gt;s&gt;&gt;p; kmp(); return 0; } 常规版
#include &lt;bits/stdc++.h&gt; using namespace std; string s,p; int nxt[100001],f[100001],n,m; void kmp(){ n=s.size(); m=p.size(); int j=0; nxt[0]=0; for(int i=1;i&lt;m;i++){ while(j&amp;&amp;p[i]!=p[j]) j=nxt[j-1]; if(p[i]==p[j]) j++; nxt[i]=j; } j=0; for(int i=0;i&lt;n;i++){ while(j==m||(j&amp;&amp;s[i]!=p[j])) j=nxt[j-1]; if(s[i]==p[j]) j++; f[i]=j; } for(int i=0;i&lt;n;i++){ if(f[i]==m)cout&lt;&lt;i&lt;&lt;endl; } } int main(){ cin&gt;&gt;s&gt;&gt;p; kmp(); return 0; } 寻找最小循环子串 字符串s是由某个子串重复连接而成的，寻找构成s的最小子串的长度
答案其实就是n-nxt[n]
#include &lt;bits/stdc++.h&gt; using namespace std; string s,p; int nxt[100001],n,m; void kmp(){y m=p.size(); int j=0; nxt[0]=0; p=p; for(int i=1;i&lt;m;i++){ while(j&amp;&amp;p[i]!=p[j]) j=nxt[j-1]; if(p[i]==p[j]) j++; nxt[i]=j; } cout&lt;&lt;m-nxt[m-1]&lt;&lt;endl; } int main(){ cin&gt;&gt;p; kmp(); return 0; } Secret word 给出字符串s，寻找最长字符串p，p满足（是s的子串，翻转后是s的前缀）
#include &lt;bits/stdc++.h&gt; using namespace std; string s; int nxt[200001],n; void kmp(){ n=s.size(); int j=0; nxt[0]=0; string t=s; reverse(t.begin(),t.end()); s=s+&#34;#&#34;+t; for(int i=1;i&lt;n*2+1;i++){ while(j&amp;&amp;s[i]!=s[j]) j=nxt[j-1]; if(s[i]==s[j]) j++; nxt[i]=j; } int ans=-1; for(int i=n;i&lt;2*n+1;i++){ ans=max(ans,nxt[i]); } for(int i=ans-1;i&gt;=0;i--)cout&lt;&lt;s[i]; } int main(){ cin&gt;&gt;s; kmp(); return 0; } exkmp 洛谷 P5410
#include &lt;bits/stdc++.h&gt; using namespace std; const int N = 2e7+10; typedef long long ll; string s,p; ll z[N*2],n,m; void exkmp(string s,string p){ n=s.size(); m=p.size(); p=p+&#34;#&#34;+s; ll L=0,R=-1; z[0]=m; for(int i=1;i&lt;n+m+1;i++){ if(i&gt;R) z[i]=0; else{ ll k=i-L; z[i]=min(z[k],R-i); } while(i+z[i]&lt;n+m+1&amp;&amp;p[z[i]]==p[i+z[i]]) ++z[i]; if(i+z[i]-1&gt;R) L=i,R=i+z[i]-1; } ll ans=0; for(int i=0;i&lt;m;i++)ans^=(1LL*(i+1)*(z[i]+1)); cout&lt;&lt;ans&lt;&lt;&#34;\n&#34;; ans=0; for(int i=0;i&lt;n;i++)ans^=(1LL*(i+1)*(z[i+m+1]+1)); cout&lt;&lt;ans&lt;&lt;&#34;\n&#34;; } int main(){ cin&gt;&gt;s&gt;&gt;p; exkmp(s,p); return 0; }
